var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CITIZEN_EXTRA_A_CHARADE","text":{"KOREA":"이게 사실이야? 시니어가 살해 당했다고?","JPN":"これ、本当？　シニアが殺されたの？","ENG":"Is it true? Was the Senior murdered?","TWN":"這是真的嗎？Senior被殺了？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"CITIZEN_EXTRA_A_CHARADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CITIZEN_EXTRA_B_CHARADE","text":{"KOREA":"그럼 이제 우린 어떻게 되는 거지? 샤레이드를 통제할 사람이 없는 건가?","JPN":"じゃあ、これから私たちはどうなるの？　シャレードを統制する人がいないってこと？","ENG":"What's going to happen to us? Is there no one to watch over Charade?","TWN":"那我們該怎麼辦？是不是沒人管理查雷德？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"CITIZEN_EXTRA_A_CHARADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_EXTRA_B_CHARADE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_EXTRA_A_CHARADE","text":{"KOREA":"루머 아닐까? 이 사진이 진짜 시니어라는 증거도 없잖아.","JPN":"デマじゃない？　この写真が本物のシニアって証拠もないし。","ENG":"Maybe it's fake. There's no proof that this is a picture of the real Senior.","TWN":"這只是一個傳言，沒有證據證明這真的是Senior。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"CITIZEN_EXTRA_A_CHARADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_EXTRA_B_CHARADE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CITIZEN_EXTRA_B_CHARADE","text":{"KOREA":"그럼 관리국은 지금 뭐하는데? 이런 논란을 방치하고 있다는 건, 문제가 있다는 반증 아니겠어?","JPN":"じゃあ、管理局は今何してるんだよ。こんなウワサを放置してるってことは、問題があるっていう証拠じゃないのか？","ENG":"What's the Administration doing, then? They're not doing anything about this. Isn't that proof that there's a problem?","TWN":"那麼管理局現在在做什麼？他們對這麼大的爭議置之不理，不就表示問題確實存在嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"CITIZEN_EXTRA_A_CHARADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_EXTRA_B_CHARADE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"메스헤르츠 채널에서 전해드리는 속보입니다.","JPN":"マスヘルツチャンネルからの速報です。","ENG":"Breaking news, here from the Masshertz channel.","TWN":"來自梅斯赫茲頻道的快報。"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"금일 갑작스러운 침식사태 발발로 인해 소란이 빚어지고 있는 가운데, SNS 등지에서는 또다른 소식으로 논란이 불거지고 있습니다.","JPN":"本日、侵食事態騒動が起きている中、SNSなどでは別の話題が広まっています。","ENG":"The abrupt Corruption disaster that occurred today has been causing chaos, while the citizens are in disarray from the news that has been spreading through social media.","TWN":"今天突然爆發的侵蝕事件讓市民一片譁然，而同時在社群網路上傳出的另一個消息引發了爭議。"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드 관리국의 시니어로 알려진 인물이 살해되었으며, 이 현장을 캡처한 다수의 사진들이 유포된 것인데요.","JPN":"シャレード管理局のシニアと思わしき人物が殺害され、その現場を撮影した写真が多数流布されました。","ENG":"A man, known as the Senior of Charade City Management, has been found murdered, and several pictures of the crime scene have been leaked.","TWN":"據悉，疑似查雷德管理局Senior的人物被殺害，現場的一些照片已經在社群網路上流傳開來。"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"해당 사진은 빠르게 삭제되었으나 그 진위 여부에 대해 관리국 관계자 측에선 아직 별다른 해명이 없는 것으로…","JPN":"この写真は直ちに削除されましたが、その真偽のほどについては管理局の関係者から、まだ弁明されていない模様です……","ENG":"The photos were quickly removed, but the Administration has made no particular statement about the authenticity of the photos...","TWN":"這些照片很快就被刪除，但管理局仍未對照片真實與否公開表態……"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"망할…!!","JPN":"クソッ……！！","ENG":"Damn it...!!","TWN":"該死……！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"벌써 언론사를 통해 일파만파로 퍼져나가고 있군. 이미 통제를 벗어났어.","JPN":"もうマスメディアを通じてあちこちに広まっているな。すでにコントロールできなくなっている。","ENG":"Word is spreading everywhere through the press. It's out of our control.","TWN":"已經透過媒體傳播開來，失去控制了。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"밀실살인극…? 지금 관리국을 상대로 뭘 하자는 거야?!","JPN":"密室殺人劇……？　管理局を相手に何をしているんだ！？","ENG":"A murder mystery...? Do they think the Administration is a joke?!","TWN":"密室殺人……？是想對管理局做什麼？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"진정하게. 어차피 평생 숨길 일도 아니었잖나.","JPN":"落ち着きたまえ。どうせずっと隠すつもりもなかったのだろう？","ENG":"Calm down. It was going to be public someday.","TWN":"冷靜點，這件事本來就不可能永遠隱瞞下去。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 가볍게 털어 넘길 문제가 아니란 거 당신도 알잖아!","JPN":"そうやって軽く済ませられる問題ではないということ、あなたも知っているじゃないか！","ENG":"You know this isn't a small issue!","TWN":"你也知道的，這事情沒那麼簡單！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리도시가 침식체들 공격을 받고 있는 상황에서 시니어가 살해당했단 사실이 퍼졌어! 심지어 그 적나라한 범행 사진이 인터넷에 뿌려지고 있다고!","JPN":"管理都市が侵食体から攻撃されている状況で、シニアが殺害されたという噂が広まった！　しかも、その赤裸々な犯行写真がネットで流布されているんだぞ！","ENG":"An Administration City is being attacked by C.O.s, and word is spreading about how the Senior was murdered! Not to mention how the gruesome photos of the crime scene are all over the internet!","TWN":"城市被侵蝕體襲擊的情況下，Senior被謀殺的消息也傳開了！甚至連犯罪現場的照片也在網路上傳開了！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"범인이 리하르트의 죽음을 공표했다는 건, 샤레이드가 혼란에 빠지길 원한단 뜻이지.","JPN":"犯人がリヒャルトの死を公表したということは、シャレードの混乱を臨んでいるのだろう。","ENG":"The culprit made Richard's death public. That means they want Charade to fall into chaos.","TWN":"兇手公開理查的死訊，就表示他想讓查雷德陷入混亂。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네마저 흥분하면 결국 그 자의 의도대로 흘러가는 꼴이 아니겠나?","JPN":"君がそうやって興奮しては、あの者の思う壺になるのではないか？","ENG":"You'd be falling into the culprit's trap if you lose your temper.","TWN":"如果連你也失去理智，不正中他的下懷了嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};